import{_ as s,a as n}from"./chunks/figure-2-failed-breakout.DiXj3LlA.js";import{_ as p,o as e,c as i,a1 as l}from"./chunks/framework.CMt7O7Ol.js";const k=JSON.parse('{"title":"第三章：突破回踩与失败突破","description":"","frontmatter":{},"headers":[],"relativePath":"trading/intraday-entry/03-breakout-retest-and-failed-breakout.md","filePath":"trading/intraday-entry/03-breakout-retest-and-failed-breakout.md"}'),t={name:"trading/intraday-entry/03-breakout-retest-and-failed-breakout.md"};function o(c,a,h,d,r,u){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="第三章-突破回踩与失败突破" tabindex="-1">第三章：突破回踩与失败突破 <a class="header-anchor" href="#第三章-突破回踩与失败突破" aria-label="Permalink to &quot;第三章：突破回踩与失败突破&quot;">​</a></h1><blockquote><p>突破本身只是市场提出方向，回踩结果才决定这个方向是否被接受。</p></blockquote><h2 id="一、突破后只有两条路径" tabindex="-1">一、突破后只有两条路径 <a class="header-anchor" href="#一、突破后只有两条路径" aria-label="Permalink to &quot;一、突破后只有两条路径&quot;">​</a></h2><p>价格离开一个关键区间后，最终只需要判断两件事：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>回踩仍留在新区间外 → 突破被接受，寻找顺势机会</span></span>
<span class="line"><span>快速回到原区间 → 突破被否定，寻找失败方向</span></span></code></pre></div><p>因此，顺势突破和失败突破并不是两套互不相关的策略。它们来自同一个问题：</p><blockquote><p>价格最终被市场接受在关键位的哪一侧？</p></blockquote><h2 id="二、什么才算有效突破" tabindex="-1">二、什么才算有效突破 <a class="header-anchor" href="#二、什么才算有效突破" aria-label="Permalink to &quot;二、什么才算有效突破&quot;">​</a></h2><p>高质量突破通常具备以下条件：</p><ol><li>突破发生在事先标记的关键位置，而不是随机发生在区间中间。</li><li>突破 K 线有清晰实体，收盘位于关键位外侧。</li><li>价格离开原区间后没有立即被完全收回。</li><li>回踩时卖方或买方无法把价格压回旧区间。</li><li>回踩后重新出现顺势推进。</li></ol><p>只有一根大 K 线并不足以证明突破有效。大 K 线也可能来自止损触发、新闻波动或短暂流动性真空。</p><p>建议把有效突破拆成三个阶段：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位移：价格明确离开旧区间</span></span>
<span class="line"><span>测试：价格回到突破位附近</span></span>
<span class="line"><span>接受：回踩守住，并重新顺势推进</span></span></code></pre></div><h2 id="三、标准顺势回踩" tabindex="-1">三、标准顺势回踩 <a class="header-anchor" href="#三、标准顺势回踩" aria-label="Permalink to &quot;三、标准顺势回踩&quot;">​</a></h2><h3 id="多头流程" tabindex="-1">多头流程 <a class="header-anchor" href="#多头流程" aria-label="Permalink to &quot;多头流程&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>价格突破阻力</span></span>
<span class="line"><span>→ 实体收在阻力上方</span></span>
<span class="line"><span>→ 等待回踩</span></span>
<span class="line"><span>→ 回踩没有重新跌入旧区间</span></span>
<span class="line"><span>→ 重新向上启动</span></span>
<span class="line"><span>→ 建立多头仓位</span></span></code></pre></div><p>失效条件：</p><ul><li>实体重新收回旧区间</li><li>回踩低点被有效跌破</li><li>价格重新站到 VWAP 下方且反弹不能收回</li><li>入场后连续数根 K 线仍无法离开突破位</li></ul><p>第一目标通常是上方下一个节点、前高或流动性区域。</p><h3 id="空头流程" tabindex="-1">空头流程 <a class="header-anchor" href="#空头流程" aria-label="Permalink to &quot;空头流程&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>价格跌破支撑</span></span>
<span class="line"><span>→ 实体收在支撑下方</span></span>
<span class="line"><span>→ 等待反抽</span></span>
<span class="line"><span>→ 反抽无法站回旧区间</span></span>
<span class="line"><span>→ 重新向下启动</span></span>
<span class="line"><span>→ 建立空头仓位</span></span></code></pre></div><p>失效条件：</p><ul><li>实体重新站回旧区间</li><li>反抽高点被有效突破</li><li>价格收回 VWAP 并完成回踩</li><li>入场后没有出现预期的向下位移</li></ul><p>第一目标通常是下方前低、下一节点或缺口边缘。</p><h2 id="四、回踩确认不是-碰线" tabindex="-1">四、回踩确认不是“碰线” <a class="header-anchor" href="#四、回踩确认不是-碰线" aria-label="Permalink to &quot;四、回踩确认不是“碰线”&quot;">​</a></h2><p>价格触碰突破位，只代表测试开始，不代表测试成功。</p><p>回踩是否成立，需要观察：</p><ul><li>回踩 K 线收在哪里</li><li>是否重新进入旧区间</li><li>是否出现连续承接或拒绝</li><li>下一根 K 线能否顺原方向推进</li><li>VWAP 和大级别结构是否支持</li></ul><p>在 1 分钟图上，可以把默认确认单位设为连续 2—3 根 K 线：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一根：回到关键位</span></span>
<span class="line"><span>第二根：测试能否收回旧区间</span></span>
<span class="line"><span>第三根：确认继续推进还是失败</span></span></code></pre></div><p>强趋势中可能只给一次很浅的回踩，但这不意味着可以在距离关键位很远的位置追单。错过第一次合理回踩，应等待下一次结构机会。</p><h2 id="五、图例一-收回关键区后的多头确认" tabindex="-1">五、图例一：收回关键区后的多头确认 <a class="header-anchor" href="#五、图例一-收回关键区后的多头确认" aria-label="Permalink to &quot;五、图例一：收回关键区后的多头确认&quot;">​</a></h2><p><img src="`+s+`" alt="历史复盘图例：收回关键区域后回踩守住"></p><p><em>图 1：价格收回关键区域，回踩没有重新跌回弱势区间，随后继续创造更高的高点。图中价格仅用于历史复盘。</em></p><p>蓝圈附近可以拆解为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位置：前期结构区</span></span>
<span class="line"><span>位移：价格向上收回关键位</span></span>
<span class="line"><span>测试：短暂回踩关键区域</span></span>
<span class="line"><span>接受：回踩守住并重新向上</span></span>
<span class="line"><span>失效：再次跌回收回区域</span></span>
<span class="line"><span>目标：上方下一结构区</span></span></code></pre></div><p>第一次向上收回只是候选信号。真正提高胜率的，是回踩后价格仍愿意停留在新区间，并再次向上推进。</p><h2 id="六、什么是失败突破" tabindex="-1">六、什么是失败突破 <a class="header-anchor" href="#六、什么是失败突破" aria-label="Permalink to &quot;六、什么是失败突破&quot;">​</a></h2><p>失败突破是指价格短暂离开关键区间，但没有在新区间获得持续接受，随后快速回到原区间。</p><p>常见结构：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>突破区间</span></span>
<span class="line"><span>→ 缺乏持续跟随</span></span>
<span class="line"><span>→ 快速收回原区间</span></span>
<span class="line"><span>→ 回测突破位</span></span>
<span class="line"><span>→ 无法重新突破</span></span>
<span class="line"><span>→ 向反方向扩张</span></span></code></pre></div><p>失败突破的重点不是“突破后马上反手”，而是等待两个确认：</p><ol><li>价格已经明确回到原区间。</li><li>再次测试突破位时无法重新站回。</li></ol><p>如果价格只是短暂回到边界附近，却很快重新站回新区间，原突破仍然可能有效。</p><h2 id="七、失败突破的标准执行" tabindex="-1">七、失败突破的标准执行 <a class="header-anchor" href="#七、失败突破的标准执行" aria-label="Permalink to &quot;七、失败突破的标准执行&quot;">​</a></h2><h3 id="向上假突破后的空头" tabindex="-1">向上假突破后的空头 <a class="header-anchor" href="#向上假突破后的空头" aria-label="Permalink to &quot;向上假突破后的空头&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>突破上沿</span></span>
<span class="line"><span>→ 快速跌回区间</span></span>
<span class="line"><span>→ 反抽上沿失败</span></span>
<span class="line"><span>→ 跌破反抽结构低点</span></span>
<span class="line"><span>→ 建立空头仓位</span></span></code></pre></div><p>失效点放在失败突破高点外，或者价格重新站上区间上沿并回踩守住的位置。</p><p>目标依次考虑：</p><ol><li>区间中轴</li><li>区间下沿</li><li>下一个结构节点</li></ol><h3 id="向下假突破后的多头" tabindex="-1">向下假突破后的多头 <a class="header-anchor" href="#向下假突破后的多头" aria-label="Permalink to &quot;向下假突破后的多头&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>跌破下沿</span></span>
<span class="line"><span>→ 快速收回区间</span></span>
<span class="line"><span>→ 回踩下沿守住</span></span>
<span class="line"><span>→ 突破回踩结构高点</span></span>
<span class="line"><span>→ 建立多头仓位</span></span></code></pre></div><p>失效点放在失败突破低点外，或者价格重新跌破区间下沿并反抽失败的位置。</p><p>目标依次考虑：</p><ol><li>区间中轴</li><li>区间上沿</li><li>上一个结构节点</li></ol><h2 id="八、图例二-冲高失败后的空头确认" tabindex="-1">八、图例二：冲高失败后的空头确认 <a class="header-anchor" href="#八、图例二-冲高失败后的空头确认" aria-label="Permalink to &quot;八、图例二：冲高失败后的空头确认&quot;">​</a></h2><p><img src="`+n+`" alt="历史复盘图例：冲高失败、反抽不过并形成下行"></p><p><em>图 2：价格冲高后快速回落，反抽无法重新站回关键区和 VWAP，随后形成更低的高点与更低的低点。图中价格仅用于历史复盘。</em></p><p>图中的空头逻辑不是看到第一根下跌 K 线就追空，而是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位置：前高和上方阻力区</span></span>
<span class="line"><span>失败：冲高后快速收回</span></span>
<span class="line"><span>测试：反抽关键区和 VWAP</span></span>
<span class="line"><span>确认：反抽站不上，结构继续向下</span></span>
<span class="line"><span>失效：重新站回关键区并回踩守住</span></span>
<span class="line"><span>目标：下方前低和下一结构节点</span></span></code></pre></div><h2 id="九、海龟汤-失败突破的一种结构" tabindex="-1">九、海龟汤：失败突破的一种结构 <a class="header-anchor" href="#九、海龟汤-失败突破的一种结构" aria-label="Permalink to &quot;九、海龟汤：失败突破的一种结构&quot;">​</a></h2><p>所谓“海龟汤”，可以简单理解为：</p><blockquote><p>价格突破一个明显区间，吸引追单并触发止损，随后迅速回到区间内，向反方向运行。</p></blockquote><p>它仍然必须遵守普通失败突破的规则：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先有清晰区间</span></span>
<span class="line"><span>→ 出现突破</span></span>
<span class="line"><span>→ 突破快速收回</span></span>
<span class="line"><span>→ 等待回测</span></span>
<span class="line"><span>→ 回测无法恢复突破</span></span>
<span class="line"><span>→ 顺失败方向入场</span></span></code></pre></div><p>不能仅凭长影线、十字星或单根反转 K 线认定海龟汤。形态必须发生在重要边界，并得到后续收线与回测确认。</p><h2 id="十、统一决策树" tabindex="-1">十、统一决策树 <a class="header-anchor" href="#十、统一决策树" aria-label="Permalink to &quot;十、统一决策树&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;价格到达关键位&quot;] --&gt; B{&quot;是否实体突破/跌破?&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B -- &quot;否&quot; --&gt; N[&quot;不交易，继续等待&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B -- &quot;是&quot; --&gt; C[&quot;不追第一根，等待回踩&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D{&quot;回踩是否留在新区间?&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D -- &quot;是&quot; --&gt; E[&quot;突破被接受&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;再次启动时顺势建仓&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D -- &quot;否&quot; --&gt; G{&quot;是否快速回到原区间?&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G -- &quot;否&quot; --&gt; N</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G -- &quot;是&quot; --&gt; H[&quot;突破被否定&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; I{&quot;再次测试能否恢复突破?&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I -- &quot;能&quot; --&gt; C</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I -- &quot;不能&quot; --&gt; J[&quot;顺失败方向建仓&quot;]</span></span></code></pre></div><h2 id="十一、仓位与止损" tabindex="-1">十一、仓位与止损 <a class="header-anchor" href="#十一、仓位与止损" aria-label="Permalink to &quot;十一、仓位与止损&quot;">​</a></h2><p>突破交易的仓位不能由“突破力度看起来很强”决定，而应由止损距离和最大允许亏损决定。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>计划风险金额 = 账户资金 × 单笔风险比例</span></span>
<span class="line"><span>允许仓位 = 计划风险金额 ÷ 每单位止损风险</span></span></code></pre></div><p>止损优先使用结构位置：</p><ul><li>顺势多头：回踩低点或旧区间内</li><li>顺势空头：反抽高点或旧区间内</li><li>失败突破空头：假突破高点外</li><li>失败突破多头：假突破低点外</li></ul><p>固定点数只能作为风险上限，不能替代结构失效。</p><p>时间也属于止损。如果入场后 2—4 根执行周期 K 线仍无法离开关键位，应当减仓或退出。</p><h2 id="十二、不做条件" tabindex="-1">十二、不做条件 <a class="header-anchor" href="#十二、不做条件" aria-label="Permalink to &quot;十二、不做条件&quot;">​</a></h2><p>以下情况不适合执行突破策略：</p><ul><li>价格位于两个关键位置中间</li><li>突破只有影线，没有实体收盘确认</li><li>突破后没有回踩，价格已经远离关键位</li><li>回踩过程中反复穿越 VWAP</li><li>主要指数明显不同步</li><li>距离下一目标太近，风险收益不足</li><li>即将公布重大数据</li><li>无法写出清晰的失效点</li></ul><h2 id="十三、第三章执行卡" tabindex="-1">十三、第三章执行卡 <a class="header-anchor" href="#十三、第三章执行卡" aria-label="Permalink to &quot;十三、第三章执行卡&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>关键位置：</span></span>
<span class="line"><span>原区间：</span></span>
<span class="line"><span>突破方向：</span></span>
<span class="line"><span>是否实体收在区间外：</span></span>
<span class="line"><span>是否完成回踩：</span></span>
<span class="line"><span>回踩最终接受在哪一侧：</span></span>
<span class="line"><span>入场触发：</span></span>
<span class="line"><span>结构失效点：</span></span>
<span class="line"><span>第一目标：</span></span>
<span class="line"><span>计划风险：</span></span>
<span class="line"><span>入场后最多等待几根 K：</span></span></code></pre></div><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><p>突破交易的核心不是追逐速度，而是等待市场证明它愿意在新区间成交。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>突破后回踩守住 → 顺势</span></span>
<span class="line"><span>突破后快速收回 → 降级</span></span>
<span class="line"><span>收回后再次测试失败 → 反向</span></span>
<span class="line"><span>没有确认 → 不做</span></span></code></pre></div><p>最值得反复练习的一句话是：</p><blockquote><p>穿过以后等回踩；回踩站稳做延续，站不稳做失败。</p></blockquote>`,85)])])}const q=p(t,[["render",o]]);export{k as __pageData,q as default};
